import store from "./base/store"
import base from './base'
function GetSystemName() {
  return 'zhima'
}

//启用的模块
function GetOpenModuleList() {
  switch (GetSystemName()) {
    case 'zhima':
      return ['redis', 'supervisor', 'command', 'git' , 'login' , 'model' , 'open_link' , 'qr_code' , 'time_transfer']
    case 'yiwei':
      return ['redis', 'supervisor', 'git' , 'command' , 'login' , 'model' , 'open_link']
    default:
      return ['redis', 'supervisor', 'git']
  }
}

//拿到redis配置
function GetRedisConfigList() {
    return require('../config/' + GetSystemName() + '/redisList.json')
}

//拿到code
function GetCodeConfigList() {
  return require('../config/' + GetSystemName() + '/codeList.json')
}

//拿到mysql配置
function GetMysqlConfigList() {
    return require('../config/' + GetSystemName() + '/mysqlList.json')
}

function GetSshConfigList(callBack){
  base.BasePost('/api/BaseSshList', {}, callBack)
}

//拿到shell配置
function GetShellConfigList() {
  switch (GetSystemName()) {
    case 'zhima':
      // eslint-disable-next-line no-case-declarations
      let configList = require('../config/zhima/shellConfigList.json')
      for(let i in configList){
        let cacheConfig = '';
        if(configList[i].name === 'wk'){
          cacheConfig = store.getStore('wkSshConfig');
        }else if(configList[i].name === 'xkf'){
          cacheConfig = store.getStore('sshConfig');
        }
        if(cacheConfig === '' || cacheConfig === undefined || cacheConfig === 'undefined'){
          continue;
        }
        let config = JSON.parse(cacheConfig)
        configList[i].username = config.username
        configList[i].password = config.password
        configList[i].host = config.host
        configList[i].port = config.port + ""
      }
      return configList
    default:
      return []
  }
}

//拿到消费者配置
function GetConsumerConfigList() {
  return require('../config/' + GetSystemName() + '/consumer.json')
}

//拿到encrypt配置
function GetEncryptConfig() {
  return require('../config/' + GetSystemName() + '/encrypt.json')
}

//拿到格式化列表
function GetFormatList() {
  return require('../config/' + GetSystemName() + '/formatResult.json')
}

export default {
  GetSystemName,
  GetOpenModuleList,
  GetRedisConfigList,
  GetMysqlConfigList,
  GetShellConfigList,
  GetEncryptConfig,
  GetCodeConfigList,
  GetConsumerConfigList,
  GetFormatList,
  GetSshConfigList,
}
