
const socketMap = {};
const socketMsg = {}
function GetSocketHost(sshId, business) {
    let unikeyConn = sshId + '#' + business
    if (socketMap[unikeyConn]) {
        return socketMap[unikeyConn]
    }
    let url = ''
    let params = 'Unikey=' + sshId + '&ShellName=' + business
    if (process.env.NODE_ENV === 'production') {
        url = 'ws://localhost:7171/socket?' + params
    } else {
        url = 'ws://localhost:7171/socket?' + params
    }
    socketMap[unikeyConn] = new WebSocket(url)
    socketMsg[unikeyConn] = ''
    return socketMap[unikeyConn]
}

function SocketExist(sshId, business){
    let unikeyConn = SocketGetUnikey(sshId , business)
    return socketMap && socketMap[unikeyConn]
}

//发送消息
function SendSocketSendMsg(unikey, shellName, msg) {
    GetSocketHost(unikey, shellName).send(msg)
}

//设置socket 创建连接回调函数
function SetSocketOnOpenFunc(unikey, shellName, callFunc) {
    GetSocketHost(unikey, shellName).onopen = () => {
        callFunc()
    }
}

//设置socket 创建链接失败回调函数
function SetSocketErrorFunc(unikey, shellName, callFunc) {
    GetSocketHost(unikey, shellName).onerror = (error) => {
        callFunc(error)
    }
}

//设置socket回调函数
function SetSocketMessageFunc(unikey, shellName, callFunc) {
    GetSocketHost(unikey, shellName).onmessage = (message) => {
        callFunc(message.data)
    }
}

function SocketGetUnikey(sshId, business){
    return sshId + '#' + business
}
//ping
function SocketPing(unikey, shellName) {
    //GetSocketHost(unikey, shellName).send(``)
}

//设置心跳
function SetSocketHeart(unikey, shellName) {
    SocketPing(unikey, shellName)
    setInterval(function () {
        SocketPing(unikey, shellName)
    }, 20000)
}

function SocketCreate(sshId , business , milliseconds , receiveMsgFunc){
    if(SocketExist(sshId , business)){
        return
    }
    SetSocketErrorFunc(sshId, business, function (error) {
        console.log('连接socket失败' , sshId , business , error)
    })
    SetSocketOnOpenFunc(sshId, business, function () {
    })
    SetSocketMessageFunc(sshId, business, function (msg) {
        let unikeyConn = SocketGetUnikey(sshId , business)
        socketMsg[unikeyConn] += msg
        receiveMsgFunc(socketMsg[unikeyConn])
        setTimeout(function () {
            let obj = document.getElementById('showShellResult')
            if (obj) {
                obj.scrollTop = obj.scrollHeight + 200
            }
        }, milliseconds)
    })
}

export default {
    SendSocketSendMsg,
    SetSocketMessageFunc,
    SetSocketErrorFunc,
    SetSocketOnOpenFunc,
    SetSocketHeart,
    SocketCreate,
    SocketExist,
}