import notify from "./notify"

let copyList = []

function SetCopyContent(content){
    copyList.push(content)
    return copyList.length
}
function handleCopy(copyIndex) {
    console.log(copyIndex , copyList)
    let copyText = copyList[parseInt(copyIndex) - 1]
    // 创建一个临时的textarea用于辅助复制操作
    const textarea = document.createElement('textarea');
    textarea.style.position = 'absolute';
    textarea.style.left = '-9999px';
    textarea.value = copyText;
    document.body.appendChild(textarea);

    // 将文本选中并执行复制操作
    textarea.select();
    document.execCommand('copy'); // 执行浏览器内置的复制命令

    // 清理临时创建的textarea
    document.body.removeChild(textarea);
    notify.success('复制成功')
}

export default {
    handleCopy,
    SetCopyContent,
}