<template>
  <el-row :gutter="10" style="background-color: #545c64;margin-left:0px;margin-right:0px;">
    <el-col :span="16">
      <el-menu :default-active="menuName" :ellipsis="false" active-text-color="#ffd04b" background-color="#545c64" mode="horizontal" router size="15" text-color="#fff" @select="handleSelect">
        <el-menu-item v-if="checkModuleOpen('redis')" index="/CacheIndex">Redis</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('supervisor')" index="/Supervisor">Supervisor</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('git')" index="/Git">Git</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('command')" index="/Command">命令集</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('login')" index="/Link">地址</el-menu-item>
        <!--      <el-menu-item index="/Docker"> Docker</el-menu-item>-->
        <el-menu-item v-if="checkModuleOpen('model')" index="/Model">Model/建表Sql</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('open_link')" index="/OpenLink">打开链接</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('qr_code')" index="/QrCode">二维码</el-menu-item>
        <el-menu-item v-if="checkModuleOpen('time_transfer')" index="/TimeTransfer">时间转换</el-menu-item>
        <!--      <el-menu-item index="/Ssh"> 终端</el-menu-item>-->
        <!--      <el-menu-item index="Tools">-->
        <!--        小工具-->
        <!--      </el-menu-item>-->
        <el-menu-item index="/Set"> 服务器配置</el-menu-item>

      </el-menu>
    </el-col>
    <el-col :span="8" style="display: flex; justify-content: center; align-items: center;">
      <el-button size="small" @click="resetConn">重新连接</el-button>
      <el-button size="small" @click="loginInfo.dialog = true">登录</el-button>
    </el-col>
  </el-row>

  <el-tag v-for="tag in tags" :key="tag.name" :type="tag.type" closable style="margin: 10px">
    {{ tag.name }}
  </el-tag>
  <el-main id="routerV">
    <router-view v-slot="{ Component }" name="home">
      <keep-alive>
        <component :is="Component" ref="currentRef" />
      </keep-alive>
    </router-view>
  </el-main>

  <el-dialog v-model="loginInfo.dialog" title="登录" width="500">
    <el-form>
      <el-form-item :label-width="80" label="username">
        <el-input v-model="loginInfo.username" autocomplete="off"/>
      </el-form-item>
      <el-form-item :label-width="80" label="password">
        <el-input v-model="loginInfo.password" autocomplete="off"/>
      </el-form-item>
    </el-form>
    <template #footer>
      <div class="dialog-footer">
        <el-button @click="loginInfo.dialog = false">取消</el-button>
        <el-button type="primary" @click="login">
          保存
        </el-button>
      </div>
    </template>
  </el-dialog>
</template>
<style>
.shellModalDrawer {
  height: 270px;
  top: initial;
  position: fixed;
}

.flex-grow {
  flex-grow: 1;
}

#routerV {
  padding-bottom: 0px;
}


.el-textarea__inner {
  background-color: rgb(84, 92, 100);
  color: #F8F8FF;
  height: 100%;
  font-size: 12px;
  font-family: Consolas;
}

.flex-grow {
  flex-grow: 10;
}

.el-textarea {
  height: 100%;
}

.shellContainer {
  position: fixed;
  width: 98%;
  bottom: 5px;
  text-align: center;
  z-index: 998;
}
</style>

<script>
import base from '../utils/base'
import mod from '../utils/module'
import socket from '../utils/base/socket'
import store from "@/utils/base/store";
import format from "@/utils/base/format"
import Clipboard from "clipboard";
import copy from "@/utils/base/copy"
import module from "@/utils/module"

export default {
  data() {
    return {
      loginInfo: {
        dialog: false,
        username: 'default',
        password: '111',
      },
      menuName: '/CacheIndex',
      minHeightMap: {
        //内容框最小高度配置
      },
      showShellMap: [
        //哪些菜单展示终端
        '/Git',
        '/Consumer',
        '/WechatKefu'
      ],
      tags: [],
      showTextarea: true,
      shellShowResult: "",
      //存储socket链接和结果
      sshMapList: [],
      xtermMapList: [],
      runCommand: '',
      openModuleList: [],
      //Xterm
      term: '',
      lastShellInfo: {
        sshId: "",
        business: "",
      }
    }
  },
  created() {
    window.handleCopy = copy.handleCopy;
  },
  mounted: function () {
    let _that = this
    //开启的服务
    _that.openModuleList = module.GetOpenModuleList()
    //登录注册
    base.BaseLogin(_that.loginInfo.username, _that.loginInfo.password, function (response) {
      if (response.ErrCode === 0) {
        store.setStore('Unikey', response.Data.unikey)
        base.BaseCheckService(function (checkResponse) {
          if (response.ErrCode === 0) {
            _that.initSshListSocket()
          } else {
            _that.$helperNotify.error('注册失败')
          }
        })
      } else {
        _that.$helperNotify.error('登录失败')
      }
    })


    //处理默认打开的页卡
    this.menuName = this.$helperStore.getStore('lastMenuName')
    if (!this.$helperConfig.getXkfDevSshConfig() || !this.$helperConfig.getWkDevSshConfig() || !this.$helperConfig.getXkfDevDbConfig()) {
      this.menuName = '/Set'
    }
    if (this.$route.path !== this.menuName && this.menuName != null) {
      this.$router.push(this.menuName)
    }
    //监听页面大小变化
    window.addEventListener('resize', function () {
      if (_that.lastShellInfo.sshId !== '') {
      }
    });
  },
  provide() {
    return {
      showTerminal: this.showTerminal,
      resizeTerminal: this.resizeTerminal,
    };
  },
  methods: {
    login: function () {
      let _that = this
      base.BaseLogin(_that.loginInfo.username, _that.loginInfo.password, function (response) {
        if (response.ErrCode === 0) {
          store.setStore('Unikey', response.Data.unikey)
          window.location.reload()
        } else {
          _that.$helperNotify.error('登录失败')
        }
      })
    },
    checkModuleOpen: function (moduleName) {
      return this.openModuleList.includes(moduleName)
    },
    resetConn: function () {
      store.removeStore('Unikey')
      // window.location.reload();
    },
    showNotify: function (notifyList) {
      this.tags = notifyList
    },
    //供子组件调用
    showTerminal(sshId, business) {
      this.lastShellInfo.sshId = sshId
      this.lastShellInfo.business = business
      this.shellSetShowResult(sshId, business)
      this.shellDrawerScrollTop(2000)
    },
    resizeTerminal: function () {

    },
    shellSetShowResult: function (sshId, business) {
      for (let i in this.sshMapList) {
        if (this.sshMapList[i].sshId === sshId && this.sshMapList[i].business === business) {
          this.shellShowResult = this.sshMapList[i].shellResult
        }
      }
    },
    shellDrawerScrollTop: function (milliseconds) {
      setTimeout(function () {
        let obj = document.getElementById('showShellResult')
        if (obj) {
          obj.scrollTop = obj.scrollHeight + 200
        }
      }, milliseconds)
    },

    handleSelect(key, keyPath) {
      let _that = this
      if (keyPath[0].indexOf('Doc-') >= 0) {
        return
      }
      this.menuName = keyPath[0]
      this.$helperStore.setStore('lastMenuName', this.menuName)

    },
    initSshSocket: function (sshId, business) {
      let _that = this
      socket.SetSocketErrorFunc(sshId, business, function (error) {
      })
      socket.SetSocketOnOpenFunc(sshId, business, function () {
        socket.SetSocketHeart(sshId, business)
        _that.sshMapList.push({
          sshId: sshId,
          business: business,
          shellResult: ''
        })
      })
      socket.SetSocketMessageFunc(sshId, business, function (msg) {
        for (let i in _that.sshMapList) {
          if (_that.sshMapList[i].sshId === sshId && _that.sshMapList[i].business === business) {
            msg = msg.replace(/\n/g, "<br />");
            msg = format.formatResult(msg, ['copy', 'color', 'replace'])
            _that.sshMapList[i].shellResult += msg
            _that.sshMapList[i].shellResult = format.formatResult(_that.sshMapList[i].shellResult, ['length'])
          }
        }
        _that.shellSetShowResult(sshId, business)
        _that.shellDrawerScrollTop(500)
      })
    },
    initSshListSocket: function () {
      let _that = this
      mod.GetSshConfigList(function (response) {
        if (response.ErrCode === 0) {
          let sshList = response.Data.ssh_list
          for (let i in sshList) {
            _that.initSshSocket(sshList[i].id, 'base') //所有socket都用base
          }
        } else {
          _that.$helperNotify.error('获取ssh列表失败')
        }
      })
    },
  },
  components: {
    Clipboard,
  },
}
</script>

<style>
.sticky-textarea {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  width: 100%;
  height: 200px;
  z-index: 9999;
}
</style>

<style scoped></style>
