//登录
import store from './base/store'
import module from './module'
import {globals} from '@/main'

//登录拿到 unikey
function BaseLogin(userName, password , okFunc) {
  BasePost(
    '/api/BaseLogin',
    {
      UserName: userName,
      Password: password,
    },
    function (response) {
      okFunc(response)
    }
  )
}

function SetIsInit(pageName){
  Globals().$pageInit[pageName] = true
}

function GetIsInit(pageName){
  if(Globals().$pageInit[pageName]){
    return Globals().$pageInit[pageName]
  }else{
    return false
  }
}

function Globals(){
  return globals
}

//注册服务
function BaseRegisterService(okFunc) {
  let redisConfigList = module.GetRedisConfigList()
  let mysqlConfigList = module.GetMysqlConfigList()
  let shellConfigList = module.GetShellConfigList()
  let encryptConfig = module.GetEncryptConfig()
  BasePost(
    '/api/BaseRegisterService',
    {
      Unikey: store.getStore('Unikey'),
      MysqlConfigList: mysqlConfigList,
      RedisConfigList: redisConfigList,
      ShellConfigList: shellConfigList,
      EncryptKey: encryptConfig['EncryptKey'],
      EncryptIv: encryptConfig['EncryptIv'],
      // eslint-disable-next-line no-unused-vars
    },
    function (response) {
      Globals().$pageInit['register'] = true
      okFunc()
    }
  )
}

//检查unikey是否已经登录注册  目前不设置账号 统一
function BaseCheckService(okFunc) {
  let unikey = store.getStore('Unikey')
  BasePost(
    '/api/BaseCheckUnikeyExist',
    {
      Unikey: unikey,
    },
    function (response) {
        BaseRegisterService(function (){
          okFunc(response)
        })
    }
  )
}

//POST请求
function BasePost(uri, params, callBack) {
  params.Unikey = store.getStore('Unikey')
  params.token = store.getStore('Unikey')
  globals.$axios.post(GetApiHost() + uri, params).then(function (response) {
    callBack(response)
  })
}

function GetUnikey() {
  return store.getStore('Unikey')
}

//拿到接口地址
function GetApiHost() {
  if (process.env.NODE_ENV === 'production') {
    return ''
  }
  return 'http://localhost:7170'
}


//页面初始化
function PageInit(pageName , preFunc , delayFunc){
  let boolInit = GetIsInit(pageName)
  let boolRegister = GetIsInit('register')
  preFunc(boolInit)
  if(boolRegister){
    delayFunc(boolInit)
  }else{
    setTimeout(function (){
      delayFunc(boolInit)
    } , 2000)
  }
}

function GetDivHeight() {
    let mainCard = document.getElementById('mainCard')
    if(!mainCard){
      return
    }
    let rect = mainCard.getBoundingClientRect();
    let viewportHeight = window.innerHeight || document.documentElement.clientHeight;
    return viewportHeight - rect.bottom - 25;
}

export default {
  BaseRegisterService,
  BaseLogin,
  BasePost,
  BaseCheckService,
  GetApiHost,
  GetUnikey,
  Globals,
  SetIsInit,
  GetIsInit,
  PageInit,
  GetDivHeight,
}
